import React from 'react';
import ParamHeader from './ParamHeader';

function ThemeSelection({ theme, onThemeChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center gap-2 mb-3">
        <ParamHeader
          paramKey="theme"
          label="主题色彩"
          iconColor="text-indigo-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.theme = el}
        />
      </div>
      <div className="flex gap-2">
        <button
          onClick={() => onThemeChange('pink')}
          className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-pink-300 to-purple-300 transition-all ${
            theme === 'pink' ? 'ring-4 ring-pink-400 scale-105 shadow-lg' : 'hover:scale-105'
          }`}
        />
        <button
          onClick={() => onThemeChange('blue')}
          className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-blue-300 to-cyan-300 transition-all ${
            theme === 'blue' ? 'ring-4 ring-blue-400 scale-105 shadow-lg' : 'hover:scale-105'
          }`}
        />
        <button
          onClick={() => onThemeChange('peach')}
          className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-orange-300 to-pink-300 transition-all ${
            theme === 'peach' ? 'ring-4 ring-orange-400 scale-105 shadow-lg' : 'hover:scale-105'
          }`}
        />
      </div>
    </div>
  );
}

export default ThemeSelection;
